            ['id' => '9503', 'penugasan_peer_id' => '866', 'kriteria_id' => '8', 'skor' => '82', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9504', 'penugasan_peer_id' => '866', 'kriteria_id' => '9', 'skor' => '83', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9505', 'penugasan_peer_id' => '866', 'kriteria_id' => '10', 'skor' => '81', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9506', 'penugasan_peer_id' => '866', 'kriteria_id' => '11', 'skor' => '83', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9507', 'penugasan_peer_id' => '866', 'kriteria_id' => '12', 'skor' => '82', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9508', 'penugasan_peer_id' => '866', 'kriteria_id' => '13', 'skor' => '81', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9509', 'penugasan_peer_id' => '866', 'kriteria_id' => '14', 'skor' => '83', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19'],
            ['id' => '9510', 'penugasan_peer_id' => '866', 'kriteria_id' => '15', 'skor' => '83', 'created_at' => '2025-09-14 20:20:19', 'updated_at' => '2025-09-14 20:20:19']
        ];

        $osById = collect($view_os)->keyBy('id');

        $resultPenugasan = collect($view_evaluator)
        ->filter(fn($item) => $osById->has($item['id']))
        ->map(function ($item) use ($osById) {
            $os = $osById[$item['id']];

            return [
                'id' => $item['id'],
                'outsourcing_id' => $os['outsourcing_id'],
                'outsourcing_nrp' => $os['outsourcing_nrp'],
                'catatan' =>  $item['catatan'],
                'penilai_id' => $item['penilai_id'],
                'penilai_nrp' => $item['penilai_nrp'],
            ];
        })
        ->values();

        $evaluasiByPenugasan = collect($evaluasis)
        ->groupBy('penugasan_peer_id');

        $resultHasMany = $resultPenugasan
        ->map(function ($penugasan) use ($evaluasiByPenugasan) {
            $penugasan['evaluasis'] =
                $evaluasiByPenugasan[$penugasan['id']] ?? collect();

            return $penugasan;
        });

        $norm = fn($value) => preg_replace('/\s+/', '', strtolower(trim((string) $value)));

        // 1) Gabungkan evaluator + os berdasarkan id
        $osById = collect($view_os)->keyBy('id');

        $resultPenugasan = collect($view_evaluator)
        ->filter(fn($item) => $osById->has($item['id']))
        ->map(function ($item) use ($osById) {
            $os = $osById[$item['id']];

            return [
                'id'             => $item['id'],
                'outsourcing_id' => $os['outsourcing_id'],
                'outsourcing_nrp' => $os['outsourcing_nrp'],
                'catatan'        => $item['catatan'] ?? null,
                'penilai_id'     => $item['penilai_id'],
                'penilai_nrp'    => $item['penilai_nrp'],
            ];
        })
        ->values();

        // 2) Group evaluasi by penugasan_peer_id
        $evaluasiByPenugasan = collect($evaluasis)
        ->groupBy('penugasan_peer_id');

        // 3) Tempel evaluasi ke penugasan
        $resultHasMany = $resultPenugasan->map(function ($penugasan) use ($evaluasiByPenugasan) {
            $penugasan['evaluasis'] = $evaluasiByPenugasan[$penugasan['id']] ?? collect();

            return $penugasan;
        });

        // 4) Ambil penugasan model dan relasinya
        $penugasanModel = PenugasanPenilai::whereHas('siklus', function ($q) {
            $q->where('title', 'Semester I Tahun 2025');
        })
        ->with([
            'evaluators:id,nip',
            'outsourcings:id,nip',
        ])
        ->get();

        // 5) Lookup penugasan berdasarkan kombinasi NIP evaluator + outsourcing
        $penugasanByKey = $penugasanModel->mapWithKeys(function ($item) use ($norm) {
            $nipEvaluator   = $norm($item->evaluators?->nip);
            $nipOutsourcing = $norm($item->outsourcings?->nip);

            if ($nipEvaluator === '' || $nipOutsourcing === '') {
                return [];
            }

            return [
                $nipEvaluator . '|' . $nipOutsourcing => $item,
            ];
        });

        DB::transaction(function () use ($resultHasMany, $penugasanByKey, $norm) {
            $penilaianBuffer = [];
            $penugasanUpdateBuffer = [];

            foreach ($resultHasMany as $row) {
                $key = $norm($row['penilai_nrp']) . '|' . $norm($row['outsourcing_nrp']);

                $penugasan = $penugasanByKey->get($key);

                if (! $penugasan) {
                    continue;
                }

                // simpan update penugasan hanya sekali per id
                $penugasanUpdateBuffer[$penugasan->id] = [
                    'status'  => 'completed',
                    'catatan' => $row['catatan'] ?? null,
                ];

                foreach ($row['evaluasis'] as $evaluasi) {
                    $uniqKey = $penugasan->id . '|' . $evaluasi['kriteria_id'];

                    $penilaianBuffer[$uniqKey] = [
                        'penugasan_id' => $penugasan->id,
                        'kriteria_id'  => $evaluasi['kriteria_id'],
                        'nilai'        => $evaluasi['skor'],
                    ];
                }
            }

            // Insert / update Penilaian tanpa dobel
            foreach ($penilaianBuffer as $data) {
                Penilaian::updateOrCreate(
                    [
                        'penugasan_id' => $data['penugasan_id'],
                        'kriteria_id'  => $data['kriteria_id'],
                    ],
                    [
                        'nilai' => $data['nilai'],
                    ]
                );
            }

            // Update status penugasan
            foreach ($penugasanUpdateBuffer as $penugasanId => $data) {
                PenugasanPenilai::whereKey($penugasanId)->update($data);
            }
        });
    }
